Rule.Source:
import sailpoint.object.Application;
import sailpoint.object.Filter;
import sailpoint.object.Identity;
import sailpoint.object.Link;
import sailpoint.object.QueryOptions;
import sailpoint.object.TaskResult;
import sailpoint.api.Terminator;
import java.util.Date;
import java.text.SimpleDateFormat; 
import sailpoint.tools.Util;
import java.util.GregorianCalendar;
import sailpoint.object.EmailOptions;
import sailpoint.object.EmailTemplate;
import java.io.File;
import java.io.FileNotFoundException;
import java.io.PrintWriter;
import sailpoint.object.EmailFileAttachment;
import sailpoint.object.EmailFileAttachment.MimeType;

import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;

private static Log log = LogFactory.getLog("ascension.rule.setCtrExpDt");

log.debug("Start of rule Ascension-Rule-SetCtrExpDt");

String company ="TNNAS";
boolean simulation = false;
int expiringWithInDays = 30;

if(config!=null){
  	company = config.get("company");
	expiringWithInDays = Integer.parseInt(config.get("expiringWithInDays"));
} 

log.debug("company: " + company);

String resultString = "";
int identitiesFound = 0;
int identitiesIterated = 0;

Filter f1 = Filter.eq("type", "contractor");
Filter f2 = Filter.eq("type", "non-hr contractor");
Filter typeFilter = Filter.or(f1, f2);

Filter inactiveFilter = Filter.eq("inactive",false);
Filter companyFilter = Filter.eq("company", company);

Filter finalFilter = Filter.and(typeFilter, inactiveFilter, companyFilter);

QueryOptions qo = new QueryOptions();
qo.addFilter(finalFilter);

Iterator it = null;
try {
   it = context.search(Identity.class, qo);
} catch (sailpoint.tools.GeneralException ge) {
   resultString += ge.getMessage() + "\n";
   taskResult.addMessage(resultString);
   return resultString;
}

StringBuilder report = new StringBuilder();


Date currentDate = new Date();

GregorianCalendar cal = new GregorianCalendar();
cal.setTime(currentDate);
cal.add(Calendar.DATE, expiringWithInDays);
 
Date expWithInDate = cal.getTime();

report.append("Identity Name,  IdentityID,  IdentityEmail, Identity External Email, Manager,  Manager Name,  Manager External Email, IdentityCube CWR ExpDate,  AD Application,  AD Expiration Date").append("\n");

while ((null != it) && (it.hasNext())) {
	
	String identityDisplayName=null;
	String identityUserName=null;
		String ctrexpDt=null;
		String managerUserName=null;
		String managerDisplayName=null;
	  String managerExtEmail=null;
	  String userExtEmail=null;
	

   Identity identity = it.next();
   if(identity != null) {
		identityDisplayName = identity.getDisplayName();
		identityUserName = identity.getName();
		identityEmail = identity.getEmail();
		ctrexpDt= identity.getAttribute("ctrexpDt");
     userExtEmail = identity.getAttribute("externalEmail");
		if (identity.getManager() !=null) {
      managerUserName=identity.getManager().getName();
      Identity mgrIdn = context.getObjectByName(Identity.class,managerUserName);
      if(null != mgrIdn){
        managerExtEmail = mgrIdn.getAttribute("externalEmail");
       }
	   managerDisplayName = identity.getManager().getDisplayName();
       
		}
	}

   List links = identity.getLinks();
   
   
   Date ctrexpDate = null;
   
   String adAppName = "";
   
   SimpleDateFormat adSDF = new SimpleDateFormat("MM/dd/yyyy hh:mm:ss a z");
   SimpleDateFormat identitySDF = new SimpleDateFormat("YYYY-MM-dd");
     
   if (links != null) {
	   for (Link link : links) {
		   if (link != null) {			   
			   if(link.getApplication().getType().equalsIgnoreCase("Active Directory - Direct")) {
				   
				   if (Util.isNotNullOrEmpty(link.getAttribute("accountExpires")) && !(link.getAttribute("accountExpires").equals("never"))) {
					   acctExpires = link.getAttribute("accountExpires");
					   Date adAccountExpiresDate = adSDF.parse(acctExpires);
					   adAppName = link.getApplicationName();
					   
					   if(ctrexpDate == null) {
						   ctrexpDate = adAccountExpiresDate; 
					   }
					   if (ctrexpDate != null) {
						   if (ctrexpDate.compareTo(currentDate) > 0) {					
							   if((adAccountExpiresDate.compareTo(ctrexpDate) < 0) && (adAccountExpiresDate.compareTo(currentDate) > 0)){
								   ctrexpDate = adAccountExpiresDate;
							   }
						   } else {
							   if(adAccountExpiresDate.compareTo(ctrexpDate) > 0) {
								   ctrexpDate = adAccountExpiresDate;
							   }
						   }
					   }
				   }
				}
			}
		}
	}
   
   identitiesIterated++;
   if (ctrexpDate != null && expWithInDate.compareTo(ctrexpDate) > 0 && ctrexpDate.compareTo(currentDate) > 0) {
		
		identitiesFound++;
		report.append('"').append(identityDisplayName).append('"').append(", ").append(identityUserName).append(", ").append(identityEmail).append(", ").append(userExtEmail).append(", ").append(managerUserName).append(", ").append('"').append(managerDisplayName).append('"').append(", ").append(managerExtEmail).append(", ").append(ctrexpDt).append(", ").append(adAppName).append(", ").append(identitySDF.format(ctrexpDate)).append("\n");
		
	}  
}



if(result != null) {
	taskResult.setAttribute("identitiesFound",identitiesFound);	
	taskResult.setAttribute("identitiesIterated",identitiesIterated);	
}


//setting up email report
Map emailArgs = new HashMap();

List emailToList = new ArrayList();
emailToList.add("IdentityCollabSailPointProv@ascension.org");
emailToList.add("leila.friedl@ascension.org");
// emailToList.add("anurag.nayak@ascension-external.org");

String subject = "Report of Expiring AD Accounts Before: "+ expWithInDate + "; Report Date: " + currentDate;

StringBuilder sb = new StringBuilder();
sb.append("Report Generation Date: ").append(currentDate).append("\n");
sb.append("AD Accounts Expiring Within Date: ").append(expWithInDate).append("\n\n");

emailArgs.put("subject", subject);
emailArgs.put("report", sb.toString());

EmailOptions emailOps = new EmailOptions(emailToList, emailArgs);
EmailTemplate emailTemplate = context.getObjectByName(EmailTemplate.class, "Ascension-EmailTemplate-ReportOfExpiringADAccts");
EmailFileAttachment fileAttachement = new EmailFileAttachment("report.csv", EmailFileAttachment.MimeType.MIME_CSV, report.toString().getBytes());
emailOps.addAttachment(fileAttachement);

context.sendEmailNotification(emailTemplate, emailOps);

return "Success";
